import {KitsDropdown} from "../../../../form/selects";
import type {EditorEl} from "../Editor";
import {useLanguage} from "../../../../_compat";

const DropdownEditor: EditorEl<{
  list:
    | {
        label: string;
        value: any;
      }[]
    | undefined;
}> = ({ list, ...options }) => {
  const {t} = useLanguage();
  const listArray = Array.isArray(list) ? list : [];
  return (
    <KitsDropdown
      attached
      id={"editor-dropdown"}
      value={options.value}
      list={listArray}
      onChange={(e: any) => options.editorCallback && options.editorCallback(e.value)}
      placeholder={t("any")}
      inputSize="sm"
    />
  );
};

export default DropdownEditor;
